body:
### Version

v20.5.1

### Platform

Darwin mbp.local 22.3.0 Darwin Kernel Version 22.3.0: Thu Jan  5 20:53:49 PST 2023; root:xnu-8792.81.2~2/RELEASE_X86_64 x86_64

### Subsystem

_No response_

### What steps will reproduce the bug?

encrypt.js:

```js
const crypto = require('crypto');
dotenv = require('dotenv');

const key = crypto.randomBytes(32);
const iv = crypto.randomBytes(16);

console.log(key, iv);

function encryptPayload(payload) {
  console.log("Payload: ", payload);
  const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);
  **const encryptedPayload = cipher.update(payload, 'utf8', 'hex');
  cipher.final('hex');**
  return encryptedPayload;
}

function decryptPayload(encryptedPayload) {
  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
  decipher.setAutoPadding(false);
  **const decryptedPayload = decipher.update(encryptedPayload, 'utf8', 'hex');
  decipher.final('utf8');**
  console.log("A- ", decryptedPayload);
  console.log("B- ", decipher);

  return decryptedPayload;
}

module.exports = {
    encryptPayload,
    decryptPayload
}
```

server.js:

```js
const express = require('express');
const jwt = require('jsonwebtoken');
const bodyParser = require('body-parser');
const { encryptPayload, decryptPayload } = require('./encrypt');

const app = express();
const port = 4000;

app.use(bodyParser.json());

// Secret key to sign JWT tokens
const secretKey = 'Zz2WHHpSYA8yVgzzeuQZiALRABSC1rh4';

// Sample user data with roles
const users = [
  { id: 1, username: 'user1', password: 'password1', role: 'user' },
  { id: 2, username: 'admin', password: 'adminpassword', role: 'admin' },
];

// Authentication middleware
const authenticateToken = (req, res, next) => {
  const token = req.header('Authorization');
  if (!token) return res.status(401).send('Unauthorized');

  jwt.verify(token, secretKey, (err, encryptedData) => {
    if (err) return res.status(403).send('Forbidden');
    console.log("Request: ", req);
    console.log("Encrypted Data: ", encryptedData);
    const decryptedData = decryptPayload(encryptedData);
    console.log("Dercypted Data: ", decryptedData);
    req.user = decryptedData.user;
    console.log("OKAY");
    next();
  });
};

app.listen(port, () => {
  console.log(`Server is running on port ${port}`);
});

app.post('/generateToken', (req, res) => {
    try{
        const { username, password } = req.body;
  
        const user = users.find((u) => u.username === username && u.password === password);
    
        if (!user) return res.status(401).send('Invalid credentials');
        let payloadData = { id: user.id, username: user.username, role: user.role };

        payloadData = JSON.stringify(payloadData);

        const encryptedPayload = encryptPayload(payloadData);
        const token = jwt.sign( encryptedPayload, secretKey);
        res.json({ token });
    } catch (err) {
        res.status(500).send({ message: "Internal Server Error", details: err.message});
    }
  });

  
  app.get('/user', authenticateToken, (req, res) => {
    console.log("Hello World", req.user);
    if (req.user.role === 'user') {
      res.send('User Content');
