share scope || context || data easily in parallel code experience

imagine  write a dynamic api generator with loadbalancer:

```js
http.createServer( ( req, res ) => {
      let servers = api_generator(req, service_cfg),
      balancer (req, res, servers, controller)
})
function balancer(req, res, servers, controller){
       let status = {}
        let bl_units = {
                http2: parallel_async function(){
                          // http2 client requet ...
                          return {target_req, target_res} || [{target_req, target_res}, ]
                }
        }
        // task distributed: a basic bl_unit: parallel running async function
        let target = bl_units[new URL("p://d"+req.url)] servers[ id ]
        // matched a server from status, then easily pipe data into running in background
        req.pipe(target.req)
        target.res.pipe(res)
        // or do parallel multi transmit
        ( parallel async function (){ req.pipe(transform); while(servers.pop()) transform.pipe(target) } )()
}
```

