body:
### What is the problem this feature will solve?

node 20.15.1. The idea is to pass around a stream without having to track the sources and being able to destroy it. So the transformer kinda starts owning control of end of life of it's source. Example use case: Implemet tail -f and abort after 5 lines. Then reading bytes is the source, and turning into lines is a transformer. The consumer (who wants to find a mysqld ready for connections in the log) should not care about the tail -f implementation.

```
stream = createSource().pipe(transformer)
stream.destroy()

```
should destroy the source, too.
This doesn't happen.

complete test case

```
// this file tests that using pipeDestroySource actually destroys
// the reader while standard .pipe() doesn't ?
import {Readable, Writable, Transform} from "node:stream";

const sleep = (ms: number) => new Promise((r) => setTimeout(r, ms))

export const pipeDestroySource = (source:  Readable,  destination: Writable) => {
    // unpipe or close might work
    destination.on('unpipe', (e) => { if (e == source) source.destroy()})
    return source.pipe(destination)
}

export type OnDestroy = () => void

class MyReadStream extends Readable {

  constructor(private ondestroy: OnDestroy) {
    super({autoDestroy: true});
  }

  _read() {
        this.push(Buffer.from("A\n"))
  }
  _destroy(err: any, callback: any) {
        console.log("MyReadStream _destroy");
    this.ondestroy()
    callback(err);
  }
} 


export class MyTransform extends Transform {

  constructor(private ondestroy: OnDestroy) {
    super({objectMode: true, autoDestroy: true});
  }

  _transform(chunk: Buffer, encoding: string, callback: any) {
        this.push(chunk)
        callback();
  }

  _destroy(err: any, callback: any){
        console.log('MyTransform _destroy');
        this.ondestroy()
        super._destroy(err, callback)
  }

}
const main = async () => {
    const test = async (title: string, pipe: (source: Readable, destination: Writable) => Writable, expectations: boolean[] ) => {
        console.log(`=== test ${title} started`);
        let r_destroy_called = false
        let t_destroy_called = false
        const r = new MyReadStream(() => { r_destroy_called = true})
        const t = new MyTransform(()  => { t_destroy_called = true })
        const s = pipe(r, t)
        s.destroy()

        // logging won't work because the events actions will be run after this method returned!
        // console.log({r_destroy_called, t_destroy_called});
        console.log(`test ${title} done`);
    }

    await test(   "pipe",
            (s, d) => s.pipe(d),
            [false, true]
        )

    await sleep(1000)

    await test(
           "pipeDestroySource",
           pipeDestroySource,
           [true, true]
       )
}

main().catch((e) => {
    console.log("== ERROR uncaught exception  ==");
    console.log(e);
    process.exit(1)
})

```


### What is the feature you are proposing to solve the problem?

```
stream = createSource().pipe(transformer, { destroySource: true })
stream.destroy()
```

### What alternatives have you considered?

using this code instead:
```
export const pipeDestroySource = (source:  Readable,  destination: Writable) => {
    // unpipe or close might work
    destination.on('unpipe', (e) => { if (e == source) source.destroy()})
    return source.pipe(destination)
}
```

text:
Title: pipe() allow destroying source!

Body:
### What is the problem this feature will solve?

node 20.15.1. The idea is to pass around a stream without having to track the sources and being able to destroy it. So the transformer kinda starts owning control of end of life of it's source. Example use case: Implemet tail -f and abort after 5 lines. Then reading bytes is the source, and turning into lines is a transformer. The consumer (who wants to find a mysqld ready for connections in the log) should not care about the tail -f implementation.

```
stream = createSource().pipe(transformer)
stream.destroy()

```
should destroy the source, too.
This doesn't happen.

complete test case

```
// this file tests that using pipeDestroySource actually destroys
// the reader while standard .pipe() doesn't ?
import {Readable, Writable, Transform} from "node:stream";

const sleep = (ms: number) => new Promise((r) => setTimeout(r, ms))

export const pipeDestroySource = (source:  Readable,  destination: Writable) => {
    // unpipe or close might work
    destination.on('unpipe', (e) => { if (e == source) source.destroy()})
    return source.pipe(destination)
}

export type OnDestroy = () => void

class MyReadStream extends Readable {

  constructor(private ondestroy: OnDestroy) {
    super({autoDestroy: true});
  }

  _read() {
        this.push(Buffer.from("A\n"))
  }
  _destroy(err: any, callback: any) {
        console.log("MyReadStream _destroy");
    this.ondestroy()
    callback(err);
  }
} 


export class MyTransform extends Transform {

  constructor(private ondestroy: OnDestroy) {
    super({objectMode: true, autoDestroy: true});
  }

  _transform(chunk: Buffer, encoding: string, callback: any) {
        this.push(chunk)
        callback();
  }

  _destroy(err: any, callback: any){
        console.log('MyTransform _destroy');
        this.ondestroy()
        super._destroy(err, callback)
  }

}
const main = async () => {
    const test = async (title: string, pipe: (source: Readable, destination: Writable) => Writable, expectations: boolean[] ) => {
        console.log(`=== test ${title} started`);
        let r_destroy_called = false
        let t_destroy_called = false
        const r = new MyReadStream(() => { r_destroy_called = true})
        const t = new MyTransform(()  => { t_destroy_called = true })
        const s = pipe(r, t)
        s.destroy()

        // logging won't work because the events actions will be run after this method returned!
        // console.log({r_destroy_called, t_destroy_called});
        console.log(`test ${title} done`);
    }

    await test(   "pipe",
            (s, d) => s.pipe(d),
            [false, true]
        )

    await sleep(1000)

    await test(
           "pipeDestroySource",
           pipeDestroySource,
           [true, true]
       )
}

main().catch((e) => {
    console.log("== ERROR uncaught exception  ==");
    console.log(e);
    process.exit(1)
})

```


### What is the feature you are proposing to solve the problem?

```
stream = createSource().pipe(transformer, { destroySource: true })
stream.destroy()
```

### What alternatives have you considered?

using this code instead:
```
export const pipeDestroySource = (source:  Readable,  destination: Writable) => {
    // unpipe or close might work
    destination.on('unpipe', (e) => { if (e == source) source.destroy()})
    return source.pipe(destination)
}
```

body:
### Version

v22.8.0

### Platform

```text
Darwin xxxMBP.lan 23.5.0 Darwin Kernel Version 23.5.0: Wed May  1 20:12:58 PDT 2024; root:xnu-10063.121.3~5/RELEASE_ARM64_T6000 arm64
```


### Subsystem

_No response_

### What steps will reproduce the bug?

`fsPromises.glob` has inconsistent `parentPath` behavior when passed `withFileTypes` option.

According to the [documentation](https://nodejs.org/api/fs.html#direntparentpath), `dirent.parentPath` should return path to the parent directory, but in some cases it doesn't.




### How often does it reproduce? Is there a required condition?

This occurs when a path is passed that does not contain a wildcard(`*`) in the filename portion.
For example, passing `./path/*/file.txt` will result in different behavior than passing `./path/to/*.txt`.

```ts
import { glob } from "fs/promises";
import path from "path";

// If the file name is a wildcard: OK
for await (const dirent of glob("./path/to/*.txt", { withFileTypes: true })) {
  console.log(dirent.parentPath);
  //=> /Users/me/work/test/path/to

  console.log(path.join(dirent.parentPath, dirent.name));
  //=> /Users/me/work/test/path/to/file.txt ✅
}

// If the file name is not a wildcard: 💣
for await (const dirent of glob("./path/*/file.txt", { withFileTypes: true })) {
  console.log(dirent.parentPath);
  //=> /Users/me/work/test/path/to/file.txt

  console.log(path.join(dirent.parentPath, dirent.name));
  //=> /Users/me/work/test/path/to/file.txt/file.txt 💣
}
```


### What is the expected behavior? Why is that the expected behavior?

`parentPath` contains the path to a file, not the path to a directory.

### What do you see instead?

The path to the file, not the path to the directory

### Additional information

As far as I can see, something similar is happening with `fs.globSync`.

text:
Title: The `parentPath` returned by `fsPromises.glob` is incorrect in some cases.

Body:
### Version

v22.8.0

### Platform

```text
Darwin xxxMBP.lan 23.5.0 Darwin Kernel Version 23.5.0: Wed May  1 20:12:58 PDT 2024; root:xnu-10063.121.3~5/RELEASE_ARM64_T6000 arm64
```


### Subsystem

_No response_

### What steps will reproduce the bug?

`fsPromises.glob` has inconsistent `parentPath` behavior when passed `withFileTypes` option.

According to the [documentation](https://nodejs.org/api/fs.html#direntparentpath), `dirent.parentPath` should return path to the parent directory, but in some cases it doesn't.




### How often does it reproduce? Is there a required condition?

This occurs when a path is passed that does not contain a wildcard(`*`) in the filename portion.
For example, passing `./path/*/file.txt` will result in different behavior than passing `./path/to/*.txt`.

```ts
import { glob } from "fs/promises";
import path from "path";

// If the file name is a wildcard: OK
for await (const dirent of glob("./path/to/*.txt", { withFileTypes: true })) {
  console.log(dirent.parentPath);
  //=> /Users/me/work/test/path/to

  console.log(path.join(dirent.parentPath, dirent.name));
  //=> /Users/me/work/test/path/to/file.txt ✅
}

// If the file name is not a wildcard: 💣
for await (const dirent of glob("./path/*/file.txt", { withFileTypes: true })) {
  console.log(dirent.parentPath);
  //=> /Users/me/work/test/path/to/file.txt

  console.log(path.join(dirent.parentPath, dirent.name));
  //=> /Users/me/work/test/path/to/file.txt/file.txt 💣
}
```


### What is the expected behavior? Why is that the expected behavior?

`parentPath` contains the path to a file, not the path to a directory.

### What do you see instead?

The path to the file, not the path to the directory

### Additional information

As far as I can see, something similar is happening with `fs.globSync`.

body:
In Node.js, the following snippet succeeds, whereas, in the browser, it throws a `DataCloneError`:

```js
structuredClone(new Response());
```

This is causing the following WPT to fail:
```js
structuredCloneBatteryOfTests.push({
  description: 'Serializing a non-serializable platform object fails',
  async f(runner, t) {
    const request = new Response();
    await promise_rejects_dom(
      t,
      "DataCloneError",
      runner.structuredClone(request)
    );
  }
});
```

text:
Title: `structuredClone` Serializing a non-serializable platform object succeeds

Body:
In Node.js, the following snippet succeeds, whereas, in the browser, it throws a `DataCloneError`:

```js
structuredClone(new Response());
```

This is causing the following WPT to fail:
```js
structuredCloneBatteryOfTests.push({
  description: 'Serializing a non-serializable platform object fails',
  async f(runner, t) {
    const request = new Response();
    await promise_rejects_dom(
      t,
      "DataCloneError",
      runner.structuredClone(request)
    );
  }
});
```

body:
## Bug Description

The memory of the Node process grows infinitely, ultimately resulting in an OOM error. Memory profiling revealed a memory leak related to AbortController.
Similar to nodejs/node#54614,but the difference is that if AbortSignal.any does not have an event listener added, AbortSignal.any will eventually be released and there will be no memory leak.

~~I am using fetch API with AbortController/AbortSignal in Node.js(not undici directly).~~
Sorry, I misremembered, I was using node:http+signal.


<!-- A clear and concise description of what the bug is. -->

## Reproducible By


<!-- A step by step list on how the bug can be reproduced for examination. -->
```js
const formatMemoryUsage = (data) =>
  `${Math.round((data / 1024 / 1024) * 100) / 100} MB`;
// let i = 0;
// const registry = new FinalizationRegistry((heldValue) => {
//   i += 1;
//   // console.debug("[registry]", heldValue);
// });
let memoryData = process.memoryUsage();
console.log("Mem before loop", formatMemoryUsage(memoryData.rss));

const run = () => {
  for (let i = 0; i < 100_000; i++) {
    const abortController = new AbortController();

    const signal = abortController.signal;

    const composedSignal = AbortSignal.any([signal]);
    composedSignal.addEventListener("abort", () => {
      // It looks like the closure reference in the callback function causes the signal to not be released?
      // console.log(signal); // Uncommenting this will aggravate the memory leak
    });

    // registry.register(signal, "signal");
  }
};
setImmediate(run);
setInterval(() => {
  if (typeof global.gc == "function") {
    global.gc(true);
  } else {
    console.warn("global.gc unavailable, need '--expose-gc' flag");
  }
  const memoryData = process.memoryUsage();
  console.log("Mem after 100K iteration", formatMemoryUsage(memoryData.rss));
  // console.log(i, "signals released");
}, 1000);

```

