    print('created temporary directory', tmpdirname)
# directory and contents have been removed
```

For bonus points it would be nice if this got cleaned up on process exit, but that's more work and it seems fine to just leave "might not get cleaned up if the process exits in the middle of your function" as a documented behavior.

### What alternatives have you considered?

We can of course just keep using `try`/`finally`, or not cleaning up.

body:
### What is the problem this feature will solve?

Does it make sense to add a method to AsyncLocalStorage that returns Disposable? 

### What is the feature you are proposing to solve the problem?

This is the example from AsyncLocalStorage using `.run`, which introduces a callback and a level of nesting that comes with that.

```typescript
http.createServer((req, res) => {
  asyncLocalStorage.run(idSeq++, () => {
    logWithId('start');
    // Imagine any chain of async operations here
    setImmediate(() => {
      logWithId('finish');
      res.end();
    });
  });
})
```

With with explicit resource management this could be:

```typescript
http.createServer((req, res) => {
  using _id = asyncLocalStorage._PROPOSED(idSeq++)

  logWithId('start');
  // Imagine any chain of async operations here
  setImmediate(() => {
    logWithId('finish');
    res.end();
  });
})
```

`enterWith` currently returns `undefined`, could that be updated to return a Disposable?

### What alternatives have you considered?

This could be built in user-land, I think
```
function enterWith<T>(als: AsyncLocalStorage<T>, store: T) {
  const oldStore = als.getStore()
  console.debug(als.enterWith(store))
  const dispose = new DisposableStack()
  dispose.defer(() => als.enterWith(oldStore))
  return dispose
}
```

text:
Title: Explicit resource management for AsyncLocalStorage

Body:
### What is the problem this feature will solve?

Does it make sense to add a method to AsyncLocalStorage that returns Disposable? 

### What is the feature you are proposing to solve the problem?

This is the example from AsyncLocalStorage using `.run`, which introduces a callback and a level of nesting that comes with that.

```typescript
http.createServer((req, res) => {
  asyncLocalStorage.run(idSeq++, () => {
    logWithId('start');
    // Imagine any chain of async operations here
    setImmediate(() => {
      logWithId('finish');
      res.end();
    });
  });
})
```

With with explicit resource management this could be:

```typescript
http.createServer((req, res) => {
  using _id = asyncLocalStorage._PROPOSED(idSeq++)

  logWithId('start');
  // Imagine any chain of async operations here
  setImmediate(() => {
    logWithId('finish');
    res.end();
  });
})
```

`enterWith` currently returns `undefined`, could that be updated to return a Disposable?

### What alternatives have you considered?

This could be built in user-land, I think
```
function enterWith<T>(als: AsyncLocalStorage<T>, store: T) {
  const oldStore = als.getStore()
  console.debug(als.enterWith(store))
  const dispose = new DisposableStack()
  dispose.defer(() => als.enterWith(oldStore))
  return dispose
}
```

body:
### What is the problem this feature will solve?

Problem

Node.js applications frequently suffer from resource leaks when developers forget to properly close files, sockets, timers, or other native resources. This is especially problematic when exceptions occur before cleanup code executes.

```js
// Current problematic pattern
function processFile(filename) {
    let fd = fs.openSync(filename, 'r')
    let timer = setInterval(() => console.log('processing'), 1000)

    // If exception occurs here, resources leak
    if (someCondition) {
        throw new Error('Processing failed')
    }

    // Cleanup code may never execute
    fs.closeSync(fd)
    clearInterval(timer)
}
```

### What is the feature you are proposing to solve the problem?

Add a built-in ResourceScope API that automatically cleans up registered resources when the scope is disposed, even during exception.

```js
{
    using scope = new ResourceScope()

    // Auto cleanup well-known nodejs objects.

    let timer = setTimeout(() => console.log('tick'), 1000)  // auto clearTimeout
    let interval = setInterval(() => console.log('interval'), 500)  // auto clearInterval

    let fd = fs.openSync('file.txt', 'r')  // auto fs.closeSync
    let stream = fs.createReadStream('data.txt')  // auto stream.close()

    let server = http.createServer()  // auto server.close()
    let child = spawn('node', ['script.js'])  // auto child.kill()
}
```

### What alternatives have you considered?


```js
import { ResourceScope } from 'node:resource'

function processFile(filename) {
    using scope = new ResourceScope()

    let fd = scope.register(fs.openSync(filename, 'r'), fs.closeSync)
    let timer = scope.register(
        setInterval(() => console.log('processing'), 1000),
        clearInterval
    )

    // Process file...
    // Resources automatically cleaned up on scope exit
}
```

text:
Title: Proposal: Resource Management Scopes for Node.js

Body:
### What is the problem this feature will solve?

Problem

Node.js applications frequently suffer from resource leaks when developers forget to properly close files, sockets, timers, or other native resources. This is especially problematic when exceptions occur before cleanup code executes.

```js
// Current problematic pattern
function processFile(filename) {
    let fd = fs.openSync(filename, 'r')
    let timer = setInterval(() => console.log('processing'), 1000)

    // If exception occurs here, resources leak
    if (someCondition) {
        throw new Error('Processing failed')
    }

    // Cleanup code may never execute
    fs.closeSync(fd)
    clearInterval(timer)
}
```

### What is the feature you are proposing to solve the problem?

Add a built-in ResourceScope API that automatically cleans up registered resources when the scope is disposed, even during exception.

```js
{
    using scope = new ResourceScope()

    // Auto cleanup well-known nodejs objects.

    let timer = setTimeout(() => console.log('tick'), 1000)  // auto clearTimeout
    let interval = setInterval(() => console.log('interval'), 500)  // auto clearInterval

    let fd = fs.openSync('file.txt', 'r')  // auto fs.closeSync
    let stream = fs.createReadStream('data.txt')  // auto stream.close()

    let server = http.createServer()  // auto server.close()
    let child = spawn('node', ['script.js'])  // auto child.kill()
}
```

### What alternatives have you considered?


```js
import { ResourceScope } from 'node:resource'

function processFile(filename) {
    using scope = new ResourceScope()

    let fd = scope.register(fs.openSync(filename, 'r'), fs.closeSync)
    let timer = scope.register(
        setInterval(() => console.log('processing'), 1000),
        clearInterval
    )

    // Process file...
    // Resources automatically cleaned up on scope exit
}
```

body:
### Version

v22.17.0

### Platform

```text
Microsoft Windows NT 10.0.26100.0 x64
```

### Subsystem

module

### What steps will reproduce the bug?

Create these files:

```js
// ModuleA.cjs
const os = require('node:os');

module.exports = {
	hello() {
		console.log('Hello Folks from', os.platform());
	}
};
```

```js
// ModuleB.cjs
const ModuleA = require('./ModuleA.cjs');

module.exports = {
	hello() {
		ModuleA.hello();
	}
};
```

```js
// ModuleC.mjs
import { createRequire } from 'node:module';
const require = createRequire(import.meta.url);
const ModuleB = require('./ModuleB.cjs');

export default {
	hello() {
		ModuleB.hello();
	}
};
```

```js
// index.mjs
import module from 'node:module';
import { pathToFileURL } from 'node:url';

const basePath = pathToFileURL(process.cwd()).toString();

module.registerHooks({
	resolve(specifier, context, nextResolve) {
		console.log(
			'context.conditions is',
			Object.prototype.toString.call(context.conditions),
			'-',
			context.parentURL.replace(basePath, '.'),
			context.conditions?.has?.('require') && 'required'
			|| context.conditions?.includes?.('import') && 'imported',
			specifier,
		);

		return nextResolve(specifier, context);
	},
});

const { default: ModuleC } = await import('./ModuleC.mjs');
ModuleC.hello();
```

Then do:
```
node index.mjs
```

Result:
```
context.conditions is [object Array] - ./index.mjs imported ./ModuleC.mjs
context.conditions is [object Array] - ./ModuleC.mjs imported node:module
context.conditions is [object Set] - ./ModuleC.mjs required ./ModuleB.cjs
context.conditions is [object Set] - ./ModuleB.cjs required ./ModuleA.cjs
context.conditions is [object Set] - ./ModuleA.cjs required node:os
Hello Folks from win32
```

### How often does it reproduce? Is there a required condition?

Consistent every time

### What is the expected behavior? Why is that the expected behavior?

context.conditions should be always a Set or an Array

### What do you see instead?

context.conditions is a Set if it comes from a require call and it is an Array if it comes from an import statement

### Additional information

_No response_

