```

### `jwt.verify()`

```typescript
namespace jwt {
  interface VerifyOptions {
    key: string | Uint8Array | CryptoKey | KeyObject;

    /**
     * Allowed algorithms
     */
    algorithms?: string[];

    /**
     * Allowed clock skew (seconds)
     */
    clockTolerance?: number;

    /**
     * Skip expiration validation
     */
    ignoreExpiration?: boolean;
  }

  interface JwtResult {
    payload: unknown;
    header: Record<string, unknown>;

    token?: {
      header: string;
